hooks.command:
python3 -c "
import json, sys, re
try:
    data = json.load(sys.stdin)
    cmd = data.get('command', '')
    if 'git commit' in cmd:
        msg_match = re.search(r'-m\s+[\"\']([^\"\']+)[\"\']', cmd)
        if msg_match:
            msg = msg_match.group(1)
            pattern = r'^(feat|fix|docs|style|refactor|test|chore|ci|perf|revert)(\([a-z][a-z0-9-]*\))?: .{1,72}$'
            if not re.match(pattern, msg):
                print(f'ERROR: Commit message does not follow Conventional Commits format.', file=sys.stderr)
                print(f'Expected: type(scope): description', file=sys.stderr)
                print(f'Got: {msg}', file=sys.stderr)
                sys.exit(1)
    if 'git checkout -b' in cmd:
        branch_match = re.search(r'git checkout -b\s+(\S+)', cmd)
        if branch_match:
            branch = branch_match.group(1)
            if branch not in ('main', 'develop'):
                if not re.match(r'^(feature|release|hotfix)/', branch):
                    print(f'ERROR: Invalid Git Flow branch name: {branch}', file=sys.stderr)
                    print(f'Expected: feature/<name>, release/v<x.y.z>, hotfix/<name>', file=sys.stderr)
                    sys.exit(1)
                if branch.startswith('release/') and not re.match(r'^release/v\d+\.\d+\.\d+', branch):
                    print(f'ERROR: Invalid release version: {branch}', file=sys.stderr)
                    print(f'Expected: release/vMAJOR.MINOR.PATCH', file=sys.stderr)
                    sys.exit(1)
    if re.search(r'git push.*(origin\s+(main|develop)|--force|-f)', cmd):
        current = ''
        import subprocess
        try:
            current = subprocess.check_output(['git', 'branch', '--show-current'], text=True).strip()
        except Exception:
            pass
        if current in ('main', 'develop') or re.search(r'origin\s+(main|develop)', cmd):
            print(f'ERROR: Direct push to main/develop is not allowed!', file=sys.stderr)
            print(f'Use feature branches and pull requests.', file=sys.stderr)
            sys.exit(1)
except Exception:
    pass
"
